// HYBRID PROCESSING V8
// 1. Accepts scraped data from Backend (route.ts)
// 2. Skips n8n Scraping (which fails on Cloudflare)
// 3. Generates Copy & Prompts with Groq

const body = $input.item.json.body || {};

// Prefer Backend Scraped Data
let title = body.scraped_title || body.product_title || 'Producto Desconocido';
let description = body.scraped_description || 'Sin descripción disponible.';
let url = body.product_url || '';
let lang = body.language || 'es';
let count = body.count || 3; // Support dynamic count

// Fallback: If backend didn't scrape good data, we could scrape here, but we trust backend more.
// We strictly format for AI.

return {
  product_url: url,
  title: title,
  description: description.substring(0, 5000),
  language: lang,
  count: count
};

const ads = $('AdSniper AI Generator').item.json.output || [];
return {
    ads: ads
};
